+    #[test]
+    fn test_join_with_cte_star_subquery_source_preserves_all_columns() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE rhs (id INTEGER, tag TEXT);")
+            .unwrap();
+        conn.execute("INSERT INTO rhs VALUES (1, 'r1');").unwrap();
+
+        let rows = conn
+            .query(
+                "SELECT s.id, s.payload, rhs.tag
+                 FROM (
+                     WITH cte AS (SELECT 1 AS id, 'left' AS payload)
+                     SELECT * FROM cte
+                 ) AS s
+                 JOIN rhs ON rhs.id = s.id;",
+            )
+            .unwrap();
+        assert_eq!(rows.len(), 1);
+        assert_eq!(rows[0].values()[0], SqliteValue::Integer(1));
+        assert_eq!(rows[0].values()[1], SqliteValue::Text("left".into()));
+        assert_eq!(rows[0].values()[2], SqliteValue::Text("r1".into()));
+    }
